import { useSignAndExecuteTransaction } from '@iota/dapp-kit';
import { useState } from 'react';
import { Transaction } from '@iota/iota-sdk/transactions';
import { FormRow } from './MoveFormsStyleHelper.tsx';
import { moveTarget, submitTx } from './MoveFormsTransactionHelper.tsx';

export function AddOwnerForm({ address }: { address: string }) {
  const { mutate: signAndExecuteTransaction } = useSignAndExecuteTransaction();
  const [digest, setDigest] = useState('');

  const [form, setForm] = useState({
    containerId: '',
    owner: '',
    role: '',
  });

  const submit = () => {
    const tx = new Transaction();

    tx.moveCall({
      target: moveTarget('add_owner'),
      arguments: [
        tx.object(form.containerId),
        tx.pure.string(form.owner),
        tx.pure.string(form.role),
      ],
    });

    submitTx(signAndExecuteTransaction, tx, address, setDigest);
  };

  return (
    <div className="d-flex justify-content-center mt-4">
      <div className="w-100" style={{ maxWidth: 560 }}>
        <h5 className="text-center mb-4">Add Owner</h5>

        <FormRow label="Container Object ID">
          <input
            className="form-control form-control-sm rounded-3"
            placeholder="0x..."
            value={form.containerId}
            onChange={(e) => setForm({ ...form, containerId: e.target.value })}
          />
        </FormRow>

        <FormRow label="Owner Address / String">
          <input
            className="form-control form-control-sm rounded-3"
            placeholder="Owner"
            value={form.owner}
            onChange={(e) => setForm({ ...form, owner: e.target.value })}
          />
        </FormRow>

        <FormRow label="Role">
          <input
            className="form-control form-control-sm rounded-3"
            placeholder="Role"
            value={form.role}
            onChange={(e) => setForm({ ...form, role: e.target.value })}
          />
        </FormRow>

        <div className="text-center mt-4">
          <button
            className="btn btn-outline-primary btn-sm px-4"
            onClick={submit}
          >
            Add Owner
          </button>
        </div>

        {digest && (
          <div className="text-center small mt-3">
            Digest: {digest}
          </div>
        )}
      </div>
    </div>
  );
}
